+name: PR - Tags Actions
+
+on:
+  pull_request:
+    types: [opened, reopened, synchronize, labeled, unlabeled]
+    branches: [master]
+
+permissions:
+  contents: read
+  pull-requests: write
+
+jobs:
+  pr-tags:
+    runs-on: ubuntu-latest
+
+    steps:
+      - name: Checkout PR head
+        uses: actions/checkout@v4
+        with:
+          ref: ${{ github.event.pull_request.head.sha }}
+
+      - name: Read comparison outputs
+        id: analysis
+        uses: actions/github-script@v7
+        with:
+          result-encoding: string
+          script: |
+            const fs = require('fs');
+
+            const analysisPath = '.changes/pr-analysis.json';
+            const changelogPath = '.changes/CHANGELOG.md';
+
+            if (!fs.existsSync(analysisPath)) {
+              core.setFailed('Missing .changes/pr-analysis.json. Run `pnpm get-changes` and commit .changes files.');
+              return '';
+            }
+
+            if (!fs.existsSync(changelogPath)) {
+              core.setFailed('Missing .changes/CHANGELOG.md. Run `pnpm get-changes` and commit .changes files.');
+              return '';
+            }
+
+            const data = JSON.parse(fs.readFileSync(analysisPath, 'utf-8'));
+            core.setOutput('impact', data.tags?.impact || 'patch');
+            core.setOutput('type', data.tags?.type || 'fix');
+            core.setOutput('build', data.tags?.build || 'build-failed');
+            core.setOutput('issues', JSON.stringify(data.issues || []));
+            core.setOutput('next_version', data.release?.nextVersion || 'unknown');
+            core.setOutput('analysis_json', JSON.stringify(data));
+            return 'ok';
+
+      - name: Ensure required labels exist
+        uses: actions/github-script@v7
+        with:
+          script: |
+            const required = [
+              { name: 'major', color: 'd73a4a', description: 'Breaking change' },
+              { name: 'minor', color: '1d76db', description: 'Backward-compatible feature' },
+              { name: 'patch', color: '9aa1a7', description: 'Backward-compatible fix' },
+              { name: 'feature', color: '2ea043', description: 'Feature change type' },
+              { name: 'fix', color: 'fbca04', description: 'Fix change type' },
+              { name: 'refactor', color: '5319e7', description: 'Refactor change type' },
+              { name: 'docs', color: '0075ca', description: 'Documentation change type' },
+              { name: 'build-passed', color: '2ea043', description: 'Package build passed' },
+              { name: 'build-failed', color: 'd73a4a', description: 'Package build failed' },
+              { name: 'test', color: 'cfd3d7', description: 'Publish as test/prerelease' }
+            ];
+
+            for (const label of required) {
+              try {
+                await github.rest.issues.createLabel({
+                  owner: context.repo.owner,
+                  repo: context.repo.repo,
+                  ...label,
+                });
+              } catch (error) {
+                if (error.status !== 422) throw error;
+              }
+            }
+
+      - name: Apply calculated labels
+        uses: actions/github-script@v7
+        env:
+          IMPACT: ${{ steps.analysis.outputs.impact }}
+          TYPE: ${{ steps.analysis.outputs.type }}
+          BUILD: ${{ steps.analysis.outputs.build }}
+        with:
+          script: |
+            const issue_number = context.issue.number;
+            const impact = process.env.IMPACT;
+            const type = process.env.TYPE;
+            const build = process.env.BUILD;
+
+            const groups = [
+              ['major', 'minor', 'patch'],
+              ['feature', 'fix', 'refactor', 'docs'],
+              ['build-passed', 'build-failed']
+            ];
+
+            for (const group of groups) {
+              for (const label of group) {
+                try {
+                  await github.rest.issues.removeLabel({
+                    owner: context.repo.owner,
+                    repo: context.repo.repo,
+                    issue_number,
+                    name: label,
+                  });
+                } catch (error) {
+                  if (error.status !== 404) throw error;
+                }
+              }
+            }
+
+            await github.rest.issues.addLabels({
+              owner: context.repo.owner,
+              repo: context.repo.repo,
+              issue_number,
+              labels: [impact, type, build],
+            });
+
+      - name: Comment analysis summary
+        uses: actions/github-script@v7
+        env:
+          ANALYSIS_JSON: ${{ steps.analysis.outputs.analysis_json }}
+          NEXT_VERSION: ${{ steps.analysis.outputs.next_version }}
+        with:
+          script: |
+            const analysis = JSON.parse(process.env.ANALYSIS_JSON);
+            const nextVersion = process.env.NEXT_VERSION;
+            const issueList = analysis.issues || [];
+            const codeChanges = analysis.comparison?.codeChanges || [];
+
+            let body = '## PR Analysis\n\n';
+            body += `- Impact: \`${analysis.tags?.impact}\`\n`;
+            body += `- Type: \`${analysis.tags?.type}\`\n`;
+            body += `- Build: \`${analysis.tags?.build}\`\n`;
+            body += `- Next version (preview): \`${nextVersion}\`\n`;
+            body += `- Code files with real diff: \`${codeChanges.length}\`\n\n`;
+
+            if (issueList.length > 0) {
+              body += '### Missing requirements / warnings\n';
+              for (const issue of issueList) body += `- ${issue}\n`;
+              body += '\n';
+            } else {
+              body += '### Missing requirements / warnings\n- None\n\n';
+            }
+
+            body += 'Generated from `.changes/pr-analysis.json` and `.changes/CHANGELOG.md`.\n';
+
+            const { data: comments } = await github.rest.issues.listComments({
+              owner: context.repo.owner,
+              repo: context.repo.repo,
+              issue_number: context.issue.number,
+            });
+
+            const marker = '## PR Analysis';
+            const existing = comments.find((c) => c.user.login === 'github-actions[bot]' && c.body.includes(marker));
+
+            if (existing) {
+              await github.rest.issues.updateComment({
+                owner: context.repo.owner,
+                repo: context.repo.repo,
+                comment_id: existing.id,
+                body,
+              });
+            } else {
+              await github.rest.issues.createComment({
+                owner: context.repo.owner,
+                repo: context.repo.repo,
+                issue_number: context.issue.number,
+                body,
+              });
+            }

